import json
import pymysql
import os

def lambda_handler(event, context):
    db_host = os.environ.get('DB_HOST')
    db_user = os.environ.get('DB_USER')
    db_password = os.environ.get('DB_PASSWORD')
    db_name = os.environ.get('DB_NAME')
    
    connection = None
    
    try:
        connection = pymysql.connect(
            host=db_host,
            user=db_user,
            password=db_password,
            database=db_name,
            charset='utf8mb4',
            cursorclass=pymysql.cursors.DictCursor
        )
        
        query_params = event.get('queryStringParameters', {})
        if query_params is None:
            query_params = {}
        
        body = {}
        if event.get('body'):
            try:
                body = json.loads(event['body'])
            except:
                body = {}
        
        params = {**query_params, **body}
        
        sql_query, sql_params = build_search_query(params)
        
        with connection.cursor() as cursor:
            cursor.execute(sql_query, sql_params)
            results = cursor.fetchall()
        
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'success': True,
                'count': len(results),
                'data': results
            }, default=str)
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'success': False,
                'error': str(e)
            })
        }
        
    finally:
        if connection:
            connection.close()


def build_search_query(params):
    base_query = "SELECT * FROM products"
    conditions = []
    sql_params = []
    
    if params.get('product_id'):
        conditions.append("product_id = %s")
        sql_params.append(params['product_id'])
    
    if params.get('name'):
        conditions.append("name LIKE %s")
        sql_params.append(f"%{params['name']}%")
    
    if params.get('category'):
        conditions.append("category = %s")
        sql_params.append(params['category'])
    
    if params.get('category_like'):
        conditions.append("category LIKE %s")
        sql_params.append(f"%{params['category_like']}%")
    
    if params.get('description'):
        conditions.append("description LIKE %s")
        sql_params.append(f"%{params['description']}%")
    
    if params.get('min_price'):
        conditions.append("price >= %s")
        sql_params.append(float(params['min_price']))
    
    if params.get('max_price'):
        conditions.append("price <= %s")
        sql_params.append(float(params['max_price']))
    
    if params.get('in_stock'):
        if params['in_stock'].lower() in ['true', '1', 'yes']:
            conditions.append("stock_quantity > 0")
    
    if params.get('min_stock'):
        conditions.append("stock_quantity >= %s")
        sql_params.append(int(params['min_stock']))
    
    if params.get('brand'):
        conditions.append("brand = %s")
        sql_params.append(params['brand'])
    
    if params.get('brand_like'):
        conditions.append("brand LIKE %s")
        sql_params.append(f"%{params['brand_like']}%")
    
    if params.get('sku'):
        conditions.append("sku = %s")
        sql_params.append(params['sku'])
    
    if params.get('status'):
        conditions.append("status = %s")
        sql_params.append(params['status'])
    
    if params.get('created_after'):
        conditions.append("created_at >= %s")
        sql_params.append(params['created_after'])
    
    if params.get('created_before'):
        conditions.append("created_at <= %s")
        sql_params.append(params['created_before'])
    
    if params.get('tags'):
        conditions.append("tags LIKE %s")
        sql_params.append(f"%{params['tags']}%")
    
    if params.get('search'):
        search_conditions = []
        search_term = f"%{params['search']}%"
        search_conditions.append("name LIKE %s")
        sql_params.append(search_term)
        search_conditions.append("description LIKE %s")
        sql_params.append(search_term)
        search_conditions.append("category LIKE %s")
        sql_params.append(search_term)
        search_conditions.append("brand LIKE %s")
        sql_params.append(search_term)
        conditions.append(f"({' OR '.join(search_conditions)})")
    
    if conditions:
        base_query += " WHERE " + " AND ".join(conditions)
    
    order_by = params.get('order_by', 'product_id')
    order_direction = params.get('order_direction', 'ASC').upper()
    
    allowed_order_fields = ['product_id', 'name', 'price', 'category', 'created_at', 'stock_quantity', 'brand']
    if order_by in allowed_order_fields and order_direction in ['ASC', 'DESC']:
        base_query += f" ORDER BY {order_by} {order_direction}"
    
    limit = params.get('limit', '100')
    try:
        limit = int(limit)
        if limit > 1000:
            limit = 1000
        base_query += f" LIMIT {limit}"
    except:
        base_query += " LIMIT 100"
    
    offset = params.get('offset', '0')
    try:
        offset = int(offset)
        base_query += f" OFFSET {offset}"
    except:
        pass
    
    return base_query, sql_params